package com.eas.ui.admin;
import com.eas.config.Database; import com.eas.util.*; import java.awt.*; import java.io.File; import java.sql.*; import javax.swing.*;
public class ReadOnlyQueryPanel extends JPanel { protected final JTable table=new JTable(); private final JTextField search=new JTextField(24); protected final String baseSql,searchSql,exportName;
 public ReadOnlyQueryPanel(String title,String baseSql,String searchSql,String exportName){this.baseSql=baseSql;this.searchSql=searchSql;this.exportName=exportName;setLayout(new BorderLayout(8,8));setBorder(BorderFactory.createEmptyBorder(12,12,12,12));JPanel top=new JPanel(new BorderLayout());top.add(UITheme.title(title),BorderLayout.WEST);JPanel actions=new JPanel();actions.add(new JLabel("Search"));actions.add(search);JButton go=UITheme.button("SEARCH");JButton reset=UITheme.button("REFRESH");JButton export=UITheme.button("EXPORT CSV");actions.add(go);actions.add(reset);actions.add(export);top.add(actions,BorderLayout.EAST);add(top,BorderLayout.NORTH);add(new JScrollPane(table),BorderLayout.CENTER);go.addActionListener(e->load(search.getText()));reset.addActionListener(e->{search.setText("");load("");});export.addActionListener(e->export());load("");}
 protected void load(String key){boolean searching=key!=null&&!key.trim().isEmpty();String sql=searching?searchSql:baseSql;try(Connection c=Database.getConnection();PreparedStatement p=c.prepareStatement(sql)){if(searching){String q="%"+key.trim()+"%";for(int i=1;i<=count(sql);i++)p.setString(i,q);}try(ResultSet r=p.executeQuery()){TableUtil.load(table,r);}}catch(Exception ex){Dialogs.error(this,ex.getMessage());}}
 private int count(String s){int n=0;for(char c:s.toCharArray())if(c=='?')n++;return n;}
 private void export(){JFileChooser fc=new JFileChooser();fc.setSelectedFile(new File(exportName+".csv"));if(fc.showSaveDialog(this)==JFileChooser.APPROVE_OPTION){try{CsvExporter.export(table,fc.getSelectedFile());Dialogs.info(this,"CSV exported.");}catch(Exception ex){Dialogs.error(this,ex.getMessage());}}}
}
